export interface LogoProps extends SVGAttributes<SVGSVGElement> {
  title?: string;
}

export function RemoolaLogo({ title = `Remoola`, className, ...props }: LogoProps) {
  return (
    <svg
      viewBox="254 218 515 392"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      role="img"
      aria-label={title}
      className={cn(className)}
      dangerouslySetInnerHTML={{ __html: LOGO_MARKUP }}
      {...props}
    />
  );
}

export function RemoolaCompactLogo({ title = `Remoola`, className, ...props }: LogoProps) {
  return (
    <svg
      viewBox="355 218 337 304"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      role="img"
      aria-label={title}
      className={cn(className)}
      dangerouslySetInnerHTML={{ __html: COMPACT_LOGO_MARKUP }}
      {...props}
    />
  );
}
